solution: ```class Solution {
    public int clumsy(int n) {
        if (n <= 2) return n;
        if (n == 3) return 6;
        int res = n * (n - 1) / (n - 2) + (n - 3);
        n -= 4;
        while (n >= 4) {
            res -= n * (n - 1) / (n - 2) - (n - 3);
            n -= 4;
        }
        if (n == 3) res -= 6;
        else if (n == 2) res -= 2;
        else if (n == 1) res -= 1;
        return res;
    }
}
```
